-- Message edit/delete CAS tests. Isolated Supabase test DB only.
begin;
select plan(8);

insert into auth.users(id,instance_id,aud,role,email,encrypted_password,email_confirmed_at,raw_app_meta_data,raw_user_meta_data,created_at,updated_at,confirmation_token,email_change,email_change_token_new,recovery_token) values
('f1000000-0000-4000-8000-000000000001','00000000-0000-0000-0000-000000000000','authenticated','authenticated','conflict-owner@picom.local',crypt('PicomTest123!',gen_salt('bf')),now(),'{}','{}',now(),now(),'','','',''),('f1000000-0000-4000-8000-000000000002','00000000-0000-0000-0000-000000000000','authenticated','authenticated','conflict-member@picom.local',crypt('PicomTest123!',gen_salt('bf')),now(),'{}','{}',now(),now(),'','','',''),('f1000000-0000-4000-8000-000000000003','00000000-0000-0000-0000-000000000000','authenticated','authenticated','conflict-mod@picom.local',crypt('PicomTest123!',gen_salt('bf')),now(),'{}','{}',now(),now(),'','','',''),('f1000000-0000-4000-8000-000000000004','00000000-0000-0000-0000-000000000000','authenticated','authenticated','conflict-visitor@picom.local',crypt('PicomTest123!',gen_salt('bf')),now(),'{}','{}',now(),now(),'','','','');
insert into public.profiles(id,username,display_name,status,status_text,accent_color) values('f1000000-0000-4000-8000-000000000001','conflict-owner','Conflict Owner','online','Test','#007571'),('f1000000-0000-4000-8000-000000000002','conflict-member','Conflict Member','online','Test','#10C2BB'),('f1000000-0000-4000-8000-000000000003','conflict-mod','Conflict Mod','online','Test','#FF772E'),('f1000000-0000-4000-8000-000000000004','conflict-visitor','Conflict Visitor','online','Test','#65717E');
insert into public.communities(id,owner_id,name,description,accent_color,visibility,public_read_enabled) values('f2000000-0000-4000-8000-000000000001','f1000000-0000-4000-8000-000000000001','Conflict fixture','Fixture','#007571','public',true);
insert into public.roles(id,community_id,name,color,level,permissions) values('f3000000-0000-4000-8000-000000000001','f2000000-0000-4000-8000-000000000001','Owner','#007571',100,'{"sendMessages":true}'),('f3000000-0000-4000-8000-000000000002','f2000000-0000-4000-8000-000000000001','Member','#10C2BB',10,'{"sendMessages":true}'),('f3000000-0000-4000-8000-000000000003','f2000000-0000-4000-8000-000000000001','Moderator','#FF772E',60,'{"deleteAnyMessage":true}');
insert into public.community_members(id,community_id,user_id,role_id) values('f4000000-0000-4000-8000-000000000001','f2000000-0000-4000-8000-000000000001','f1000000-0000-4000-8000-000000000001','f3000000-0000-4000-8000-000000000001'),('f4000000-0000-4000-8000-000000000002','f2000000-0000-4000-8000-000000000001','f1000000-0000-4000-8000-000000000002','f3000000-0000-4000-8000-000000000002'),('f4000000-0000-4000-8000-000000000003','f2000000-0000-4000-8000-000000000001','f1000000-0000-4000-8000-000000000003','f3000000-0000-4000-8000-000000000003');
insert into public.channels(id,community_id,name,type,topic,is_private,public_read_enabled,position) values('f5000000-0000-4000-8000-000000000001','f2000000-0000-4000-8000-000000000001','conflicts','text','Public',false,true,1);
insert into public.messages(id,community_id,channel_id,author_id,body,client_message_id) values('f6000000-0000-4000-8000-000000000001','f2000000-0000-4000-8000-000000000001','f5000000-0000-4000-8000-000000000001','f1000000-0000-4000-8000-000000000002','Original','conflict-member-message'),('f6000000-0000-4000-8000-000000000002','f2000000-0000-4000-8000-000000000001','f5000000-0000-4000-8000-000000000001','f1000000-0000-4000-8000-000000000001','Moderate me','conflict-owner-message');

select set_config('request.jwt.claim.sub','f1000000-0000-4000-8000-000000000002',true); set local role authenticated;
select is((select body from public.edit_message_with_version('f6000000-0000-4000-8000-000000000001','First edit',null)),'First edit','first compare-and-set edit succeeds');
select throws_like($$select * from public.edit_message_with_version('f6000000-0000-4000-8000-000000000001','Stale edit',null)$$,'%MESSAGE_VERSION_CONFLICT%','stale edit cannot overwrite newer state');
select throws_like($$select * from public.delete_message_with_version('f6000000-0000-4000-8000-000000000001',null)$$,'%MESSAGE_VERSION_CONFLICT%','stale delete requires review');
select ok((select deleted_at is not null from public.delete_message_with_version('f6000000-0000-4000-8000-000000000001',(select edited_at from public.messages where id='f6000000-0000-4000-8000-000000000001'))),'current version delete succeeds');
select throws_like($$select * from public.edit_message_with_version('f6000000-0000-4000-8000-000000000001','Resurrect',null)$$,'%MESSAGE_DELETED_CONFLICT%','delete wins over later edit');
select throws_like($$update public.messages set body='Bypass' where id='f6000000-0000-4000-8000-000000000001'$$,'%permission denied%','direct client update is revoked'); reset role;

select set_config('request.jwt.claim.sub','f1000000-0000-4000-8000-000000000003',true); set local role authenticated;
select ok((select deleted_at is not null from public.delete_message_with_version('f6000000-0000-4000-8000-000000000002',null)),'moderator permission can soft delete'); reset role;
select set_config('request.jwt.claim.sub','f1000000-0000-4000-8000-000000000004',true); set local role authenticated;
select throws_like($$select * from public.delete_message_with_version('f6000000-0000-4000-8000-000000000002',null)$$,'%MESSAGE_DELETE_FORBIDDEN%','visitor cannot delete messages'); reset role;

select * from finish(); rollback;
